func (q *Queries) StartRunLease(ctx context.Context, arg StartRunLeaseParams) (StartRunLeaseRow, error) {
	row := q.db.QueryRow(ctx, startRunLease,
		arg.ExpiresAt,
		arg.OrgID,
		arg.RunID,
		arg.RunLeaseID,
		arg.LeaseSequence,
		arg.WorkerInstanceID,
		arg.WorkerEpoch,
		arg.RuntimeInstanceID,
		arg.NetworkSlotID,
		arg.NetworkSlotGeneration,
		arg.ExpectedRunStateVersion,
	)
	var i StartRunLeaseRow
	err := row.Scan(
		&i.ID,
		&i.OrgID,
		&i.ProjectID,
		&i.EnvironmentID,
		&i.RunID,
		&i.WorkspaceID,
		&i.RegionID,
		&i.LeaseSequence,
		&i.TaskAttemptNumber,
		&i.WorkerGroupID,
		&i.WorkerInstanceID,
		&i.WorkerEpoch,
		&i.RuntimeInstanceID,
		&i.NetworkSlotID,
		&i.NetworkSlotGeneration,
		&i.QueueName,
		&i.QueueClass,
		&i.ConcurrencyKey,
		&i.QueueConcurrencyLimit,
		&i.RuntimeIdentityID,
		&i.WorkerProtocolVersion,
		&i.RequestedCpuMillis,
		&i.RequestedMemoryBytes,
		&i.RequestedWorkloadDiskBytes,
		&i.RequestedScratchBytes,
		&i.RequestedExecutionSlots,
		&i.ResourceSnapshot,
		&i.TraceID,
		&i.SpanID,
		&i.ParentSpanID,
		&i.Traceparent,
		&i.State,
		&i.AssignedAt,
		&i.StartDeadlineAt,
		&i.ClaimedAt,
		&i.StartedAt,
		&i.RenewedAt,
		&i.ExpiresAt,
		&i.CheckpointedAt,
		&i.TerminalAt,
		&i.TerminalReasonCode,
		&i.TerminalError,
		&i.TerminalRequestFingerprint,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
